import{_ as t,c as a,o as i,aj as r}from"./chunks/framework.guNMSiFm.js";const u=JSON.parse('{"title":"Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/index.md","filePath":"guide/best-practices/index.md","lastUpdated":1777621302000}'),n={name:"guide/best-practices/index.md"};function o(s,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h1><p>This section collects production-oriented guidance for Iroha applications and networks. It is organized by the decision you need to make, not by the feature that happens to implement it.</p><p>Use it as a checklist before a shared testnet rehearsal, a production launch, or a major client release.</p><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Focus</th></tr></thead><tbody><tr><td><a href="./application-development.html">Application Development</a></td><td>Client configuration, transaction submission, retries, events, queries, and agent-assisted development</td></tr><tr><td><a href="./data-modeling.html">Data Modeling</a></td><td>Domains, accounts, assets, NFTs, metadata, off-chain data, and naming conventions</td></tr><tr><td><a href="./network-deployment.html">Network Deployment</a></td><td>Genesis, topology, peer keys, Torii exposure, consensus settings, and environment separation</td></tr><tr><td><a href="./operations.html">Operations</a></td><td>Observability, runbooks, backups, change management, capacity checks, and incident handling</td></tr><tr><td><a href="./security-and-access.html">Security and Access</a></td><td>Secret handling, permissions, technical accounts, network access, and audit trails</td></tr><tr><td><a href="./release-readiness.html">Release Readiness</a></td><td>Localnet, Taira, Minamoto, compatibility checks, live-network safeguards, and rollback planning</td></tr></tbody></table><h2 id="cross-cutting-rules" tabindex="-1">Cross-Cutting Rules <a class="header-anchor" href="#cross-cutting-rules" aria-label="Permalink to &quot;Cross-Cutting Rules&quot;">​</a></h2><ul><li>Keep local development, shared testnet, and production configuration separate.</li><li>Treat genesis, peer topology, executor policy, and key material as controlled deployment artifacts.</li><li>Model durable ledger state intentionally. Do not use metadata as a dumping ground for large, private, or high-churn data.</li><li>Submit transactions through idempotent workflows that can handle rejection, expiry, retries, and delayed status.</li><li>Prefer narrow permissions, dedicated technical accounts, and explicit operational runbooks over broad administrator access.</li><li>Prove behavior on a disposable local network first, then rehearse on Taira or another shared testnet before any mainnet operation.</li></ul><h2 id="related-references" tabindex="-1">Related References <a class="header-anchor" href="#related-references" aria-label="Permalink to &quot;Related References&quot;">​</a></h2><ul><li><a href="/iroha-2-docs/guide/configure/overview.html">Configuration and Management</a></li><li><a href="/iroha-2-docs/guide/security/">Security</a></li><li><a href="/iroha-2-docs/guide/advanced/metrics.html">Performance and Metrics</a></li><li><a href="/iroha-2-docs/reference/compatibility-matrix.html">Compatibility Matrix</a></li><li><a href="/iroha-2-docs/reference/torii-endpoints.html">Torii Endpoints</a></li><li><a href="/iroha-2-docs/reference/permissions.html">Permission Tokens</a></li></ul>',9)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
